THE CLAIM:
{
 "title": "Year-1 market share is set by a 3-5 year benchmark, too high",
 "narrative": "The model says the venture wins 3% of its serviceable market in Year 1. But the benchmarks behind that 3% describe what companies capture over 1 to 5 years, and the one real comparable entrant, Tractian, started at about 0.1% of its market. Read at a 12-month grain, the Year-1 number is roughly 5 times too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "The 3% benchmark describes 1 to 5 year windows, not 12 months",
   "refs": [
    "digest:obtainable-benchmark#c1",
    "digest:obtainable-benchmark#c4",
    "profile:Stage"
   ]
  },
  {
   "step": "propagation",
   "text": "Real first-year shares fall to 0.1%, far below the 1% floor",
   "refs": [
    "digest:obtainable-benchmark#c5",
    "digest:obtainable-benchmark#c6",
    "digest:obtainable-benchmark#c7"
   ]
  },
  {
   "step": "model-impact",
   "text": "A 3% rate overstates Year-1 revenue by about 5 times",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "Any named comparable industrial B2B entrant with documented first-year revenue at or above 1% of its stated market.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Calculating market size with TAM, SAM and SOM for startups",
   "sourceType": "industry-report",
   "publisher": "Wise",
   "date": "2026-01-21",
   "excerpt": "Serviceable Obtainable Market (SOM): The realistic share of SAM you expect to capture in the next three to five years, accounting for competition and your execution capacity.",
   "url": "https://wise.com/gb/blog/tam-sam-vs-som",
   "attached": true
  },
  {
   "title": "Tractian: How Two Sons of Factory Engineers Built a $32M Business",
   "sourceType": "triangulation",
   "publisher": "Solopreneur",
   "date": "2026-05-30",
   "excerpt": "The company grew from $200K to $32M in revenue over four years and serves more than 1,000 plants... Market $14.9 млрд.",
   "url": "https://solopreneuro.com/en/ideas/tractian-maintenance-ai",
   "attached": true
  },
  {
   "title": "What is SOM? | Angel Investors Network Glossary",
   "sourceType": "industry-report",
   "publisher": "Angel Investors Network",
   "date": null,
   "excerpt": "the portion of the Serviceable Addressable Market that a company can realistically capture within a specific timeframe, typically 3-5 years",
   "url": "https://angelinvestorsnetwork.com/glossary/serviceable-obtainable-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.03,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.01,
   "high": 0.05
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Year-1 SOM benchmarks: 1% of SAM (Prospeo); early-stage range 1–5% (IdeaPlan) → curated 3% mid-band",
   "crossCheck": "Prior 6% assumption sat above every year-1 benchmark found — revised down"
  },
  "provenance": {
   "rationale": "Two independent benchmark sources agree on 1–5%, but both are generic (not DC-hardware-specific) → inferred.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
